const rows = $input.all().map(i => i.json);
const groups = {};

rows.forEach(row => {
  const tid = row.task_id;
  if (!groups[tid]) {
    groups[tid] = {
      task_id: tid,
      applicant_name: row.applicant_name,
      staff_id: row.staff_id,
      department: row.department,
      status: row.status || "Submitted",
      apply_date: row.created_at,
      close_date: row.updated_at,
      total_amount: 0,
      items: []
    };
  }

  if (row.item_name) {
    groups[tid].items.push({
      name: row.item_name,
      qty: Number(row.quantity) || 0,
      subtotal: Number(row.subtotal) || 0
    });
    groups[tid].total_amount += Number(row.subtotal) || 0;
  }
});

const allOrders = Object.values(groups);
const active = allOrders.filter(o => !['ready', 'submitted', 'done', 'closed'].includes(o.status.toLowerCase()));
const archived = allOrders.filter(o => ['ready', 'submitted', 'done', 'closed'].includes(o.status.toLowerCase()));

return { active, archived };

/* ======================================================
 * 終極修正版：處理欄位名稱有空白字元的問題
 * ====================================================== */

// 1. 取得所有輸入
const allItems = $input.all();

// 2. 分類容器
const applications = [];
const items = [];

// 3. 分類邏輯（忽略欄位名稱的空白）
for (const item of allItems) {
    const data = item.json;
    const keys = Object.keys(data);

    // 找出真正的欄位名稱（不管有沒有空白）
    const hasItemName = keys.some(k => k.trim() === 'item_name');
    const hasTaskId = keys.some(k => k.trim() === 'task_id');

    // A. 有 item_name 就是明細
    if (hasItemName) {
        items.push(data);
    } 
    // B. 沒有 item_name 但有 task_id 就是主檔
    else if (hasTaskId) {
        applications.push(data);
    }
}

// 4. 建立明細對照表（處理空白欄位名）
const itemsMap = {};
for (const row of items) {
    const keys = Object.keys(row);

    // 找出 task_id 欄位（不管有沒有空白）
    const taskIdKey = keys.find(k => k.trim() === 'task_id');
    const itemNameKey = keys.find(k => k.trim() === 'item_name');
    const qtyKey = keys.find(k => k.trim() === 'quantity');
    const subtotalKey = keys.find(k => k.trim() === 'subtotal');

    const taskId = String(row[taskIdKey] || '').trim();
    if (!taskId) continue;

    if (!itemsMap[taskId]) itemsMap[taskId] = [];

    itemsMap[taskId].push({
        item_name: row[itemNameKey] || '未知商品',
        quantity: Number(row[qtyKey]) || 0,
        subtotal: Number(row[subtotalKey]) || 0
    });
}

// 5. 組合訂單
const active = [];
const archived = [];

for (const app of applications) {
    const keys = Object.keys(app);
    const taskIdKey = keys.find(k => k.trim() === 'task_id');

    const taskId = String(app[taskIdKey] || '').trim();
    if (!taskId) continue;

    const statusKey = keys.find(k => k.trim() === 'status');
    const statusRaw = String(app[statusKey] || '').toLowerCase();

    // 取得其他欄位（處理空白）
    const getField = (obj, fieldName) => {
        const key = Object.keys(obj).find(k => k.trim() === fieldName);
        return obj[key];
    };

    // 計算總金額
    let total = Number(getField(app, 'total_amount')) || 0;
    const orderItems = itemsMap[taskId] || [];

    if (total === 0 && orderItems.length > 0) {
        total = orderItems.reduce((sum, i) => sum + i.subtotal, 0);
    }

const order = {
  task_id: taskId,
  date: getField(app, 'created_at') || getField(app, 'date'), 
  user: getField(app, 'applicant_name') || getField(app, 'user'),
  staff_id: getField(app, 'staff_id'),
  phone: getField(app, 'applicant_phone'),
  email: getField(app, 'applicant_email'),
  department: getField(app, 'department'),
  cost_center: getField(app, 'cost_center'),
  reason: getField(app, 'reason'),
  status: getField(app, 'status') || 'Pending',
  items: orderItems,
  total: total,
  comment: getField(app, 'review_comment') || getField(app, 'comment') || '', // 新增這一行
};

    if (['done', 'closed', 'rejected'].includes(statusRaw)) {
        archived.push(order);
    } else {
        active.push(order);
    }
}

// 6. 直接回傳最終格式
return {
    orders: {
        active: active,
        archived: archived
    }
};

/**
 * 修正版：對接 MySQL 節點並組合郵件資料
 */

// 1. 從「Update-Applications」節點抓取申請人基本資訊 (姓名與 Email)
const orderData = $('Update-Applications').first().json;
const user = orderData.applicant_name || '申請人';
const email = orderData.applicant_email || '';

// 2. 從 Webhook 原始資料抓取 task_id
// 這樣最保險，避免中間節點遺失欄位
const taskId = $('Webhook-更新訂單狀態').item.json.body.task_id;

// 3. 從「Update-Application_Items」節點抓取該單所有商品明細
const items = $('Update-Application_Items').all();

let itemList = '';
let total = 0;

// 4. 迴圈處理商品清單並計算總金額
items.forEach((item, i) => {
  const name = item.json.item_name || '未知商品';
  const qty = Number(item.json.quantity) || 1;
  const subtotal = Number(item.json.subtotal) || 0;

  total += subtotal;
  itemList += `${i + 1}. ${name} x${qty} - $${subtotal}\n`;
});

// 5. 回傳給 Gmail 節點使用的格式
return [{
  json: {
    user: user,
    task_id: taskId,
    email: email,
    item_list: itemList,
    total: total,
    item_count: items.length
  }
}];

// 1. 從 MySQL 節點抓取申請人資訊 (對接 Update-Applications1)
const orderData = $('Update-Applications1').first().json;
const user = orderData.applicant_name || '申請人';
const email = orderData.applicant_email || '';

// 2. 從 Webhook 原始資料抓取 task_id 與 異常原因 (comment)
const webhookData = $('Webhook-更新訂單狀態').item.json.body;
const taskId = webhookData.task_id;
const comment = webhookData.comment || '未提供具體原因';

// 3. 從「Update-Application_Items1」節點抓取該單所有商品明細
const items = $('Update-Application_Items1').all();

let itemList = '';
let total = 0;

// 4. 迴圈處理商品清單
items.forEach((item, i) => {
  const name = item.json.item_name || '未知商品';
  const qty = Number(item.json.quantity) || 1;
  const subtotal = Number(item.json.subtotal) || 0;

  total += subtotal;
  itemList += `${i + 1}. ${name} x${qty} - $${subtotal}\n`;
});

// 5. 回傳給 Gmail 節點使用的格式
return [{
  json: {
    user: user,
    task_id: taskId,
    email: email,
    comment: comment,
    item_list: itemList,
    total: total,
    item_count: items.length
  }
}];

const allItems = $input.all();
const formattedItems = allItems.map(item => {
    const data = item.json;
    return {
        item_id: data.item_id,
        item_name: data.item_tw, 
        unit_price: Number(data.price) || 0,
        stock: Number(data.inventory) || 0,
        // 關鍵修正：改為 data.image
        image: data.image || "" 
    };
});
return { items: formattedItems };

// 使用 $(名稱).all() 取代 $node[名稱].all()
const webhookItem = $("Webhook-儲存商品2").item.json.body;
const sheetItems = $("讀取items_list").all();

// --- 自動編號邏輯 ---
let finalId = webhookItem.item_id;
if (!finalId || finalId.startsWith('new_')) {
    let maxNum = 0;
    sheetItems.forEach(item => {
        const currentId = String(item.json.item_id || '');
        const match = currentId.match(/(\d+)$/);
        if (match) {
            const num = parseInt(match[1], 10);
            if (num > maxNum) maxNum = num;
        }
    });
    finalId = `ID-${(maxNum + 1).toString().padStart(3, '0')}`;
}

// --- 圖片轉二進位邏輯 ---
const base64Data = webhookItem.image_data;
let binaryData = {}; // 修正：初始化為空物件

if (base64Data) {
    // 如果帶有 data:image 標頭則移除
    const base64String = base64Data.includes(',') ? base64Data.split(',')[1] : base64Data;

    // 修正：binary 物件結構必須精確
    binaryData['file0'] = {
        data: base64String,
        fileName: `${finalId}.jpg`,
        mimeType: 'image/jpeg',
    };
}

return [{
    json: {
        ...webhookItem,
        item_id: finalId,
        hasImage: !!base64Data
    },
    // 如果沒有圖片，回傳 undefined 讓 IF 節點判斷
    binary: Object.keys(binaryData).length > 0 ? binaryData : undefined
}];

